CREATE FUNCTION refresh_note_checklist_search() RETURNS TRIGGER AS $$
BEGIN
    IF TG_OP IN ('DELETE', 'UPDATE') THEN
        UPDATE notes n
        SET checklist_search_text = coalesce((
            SELECT string_agg(i.text, ' ' ORDER BY i.sort_order, i.id)
            FROM checklist_items i
            WHERE i.owner_id = OLD.owner_id AND i.note_id = OLD.note_id
        ), '')
        WHERE n.owner_id = OLD.owner_id AND n.id = OLD.note_id;
    END IF;
    IF TG_OP IN ('INSERT', 'UPDATE') THEN
        UPDATE notes n
        SET checklist_search_text = coalesce((
            SELECT string_agg(i.text, ' ' ORDER BY i.sort_order, i.id)
            FROM checklist_items i
            WHERE i.owner_id = NEW.owner_id AND i.note_id = NEW.note_id
        ), '')
        WHERE n.owner_id = NEW.owner_id AND n.id = NEW.note_id;
    END IF;
    RETURN coalesce(NEW, OLD);
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_checklist_search_insert
AFTER INSERT ON checklist_items
FOR EACH ROW EXECUTE FUNCTION refresh_note_checklist_search();

CREATE TRIGGER trg_checklist_search_update
AFTER UPDATE OF text, sort_order, note_id ON checklist_items
FOR EACH ROW EXECUTE FUNCTION refresh_note_checklist_search();

CREATE TRIGGER trg_checklist_search_delete
AFTER DELETE ON checklist_items
FOR EACH ROW EXECUTE FUNCTION refresh_note_checklist_search();

public Instant lastSnapshotAt(OwnerId ownerId, UUID noteId) {
    List<?> rows = entityManager.createNativeQuery(
        "select last_snapshot_at from notes where owner_id = :owner and id = :note")
        .setParameter("owner", ownerId.value()).setParameter("note", noteId).getResultList();
    if (rows.isEmpty() || rows.get(0) == null) return null;
    Object value = rows.get(0);
    if (value instanceof Instant instant) return instant;
    if (value instanceof Timestamp timestamp) return timestamp.toInstant();
    return ((OffsetDateTime) value).toInstant();
}

